"use client";

import { useBackgroundMusic } from "@/hooks/use-background-music";
import { Music2 } from "lucide-react";

interface MusicDockProps {
  title: string;
  description: string;
}

export function MusicDock({ title, description }: MusicDockProps) {
  const { isPlaying, play, stop } = useBackgroundMusic();

  return (
    <div className="fixed bottom-4 right-4 z-50 sm:bottom-6 sm:right-6">
      {/* Self-contained styling for specialized music pacifier animations */}
      <style>{`
        @keyframes pacifierWiggle {
          0%, 100% { transform: rotate(-10deg) translateY(0px) scale(1); }
          50% { transform: rotate(10deg) translateY(-3px) scale(1.05); }
        }
        @keyframes ringSpin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
        @keyframes noteFloat1 {
          0% { transform: translate(0, 0) scale(0.6) rotate(0deg); opacity: 0; }
          20% { opacity: 0.8; }
          100% { transform: translate(14px, -60px) scale(1.15) rotate(20deg); opacity: 0; }
        }
        @keyframes noteFloat2 {
          0% { transform: translate(0, 0) scale(0.6) rotate(0deg); opacity: 0; }
          20% { opacity: 0.8; }
          100% { transform: translate(-16px, -65px) scale(1.15) rotate(-25deg); opacity: 0; }
        }
        @keyframes noteFloat3 {
          0% { transform: translate(0, 0) scale(0.5) rotate(0deg); opacity: 0; }
          20% { opacity: 0.8; }
          100% { transform: translate(10px, -50px) scale(1) rotate(15deg); opacity: 0; }
        }
        .anim-pacifier-music {
          animation: pacifierWiggle 1.6s ease-in-out infinite;
          transform-origin: center center;
        }
        .anim-ring-spin {
          animation: ringSpin 4s linear infinite;
          transform-origin: 24px 37px; /* Center of pacifier ring */
        }
        .note-1 {
          animation: noteFloat1 2.4s linear infinite;
        }
        .note-2 {
          animation: noteFloat2 2.4s linear infinite;
          animation-delay: 0.8s;
        }
        .note-3 {
          animation: noteFloat3 2.4s linear infinite;
          animation-delay: 1.6s;
        }
      `}</style>

      <button
        type="button"
        onClick={isPlaying ? stop : play}
        className={`group relative flex h-16 w-16 items-center justify-center rounded-full border border-white/80 bg-white/92 shadow-[0_18px_45px_rgba(59,130,246,0.22)] backdrop-blur-xl transition hover:-translate-y-0.5 hover:shadow-[0_24px_60px_rgba(59,130,246,0.3)] cursor-pointer outline-none ${
          isPlaying ? "ring-2 ring-sky-300" : ""
        }`}
        aria-label={isPlaying ? "Pausar música" : "Reproducir música"}
      >
        {/* Animated Floating Music Notes when playing */}
        {isPlaying && (
          <>
            <span className="note-1 absolute top-2 right-2 text-xs select-none">🎵</span>
            <span className="note-2 absolute top-2 left-2 text-xs select-none">🎶</span>
            <span className="note-3 absolute top-1 left-6 text-[10px] select-none">✨</span>
          </>
        )}

        {/* Custom Pacifier SVG Container */}
        <div className={`relative w-11 h-11 flex items-center justify-center ${isPlaying ? "anim-pacifier-music" : ""}`}>
          <svg
            width="44"
            height="44"
            viewBox="0 0 48 48"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            className="w-full h-full select-none"
          >
            {/* Nipple (Chupón) */}
            <path
              d="M24 6 C20 6, 18 10, 18 15 C18 20, 21 21, 24 21 C27 21, 30 20, 30 15 C30 10, 28 6, 24 6 Z"
              fill="#FFD166"
              opacity="0.85"
            />
            
            {/* Shield (Guard) */}
            <rect x="10" y="21" width="28" height="6" rx="3" fill="#38BDF8" stroke="#FFFFFF" strokeWidth="1.5" />
            <circle cx="24" cy="24" r="5.5" fill="#0284C7" />
            
            {/* Handle Ring - Spins when playing */}
            <g className={isPlaying ? "anim-ring-spin" : ""}>
              <path
                d="M24 29 C28.5 29, 32 32.5, 32 37 C32 41.5, 28.5 45, 24 45 C19.5 45, 16 41.5, 16 37 C16 32.5, 19.5 29, 24 29 Z"
                stroke="#38BDF8"
                strokeWidth="3.5"
                fill="none"
              />
              {/* Decorative baby crown or tie emblem on ring */}
              <circle cx="24" cy="40" r="2.5" fill="#FBBF24" />
            </g>

            {/* Tiny Sunglasses details overlay for theme */}
            <path
              d="M20 23 L22 23.5 M26 23 L28 23.5"
              stroke="#1E293B"
              strokeWidth="1.2"
              strokeLinecap="round"
              opacity="0.75"
            />
          </svg>
        </div>

        {/* Accessibility screen-reader fallback */}
        <span className="sr-only">
          {title}: {description}
        </span>
        <Music2 className="hidden" />
      </button>
    </div>
  );
}
export default MusicDock;
