export function SkyBackground() {
  const [scrollY, setScrollY] = useState(0);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const handleScroll = () => {
      setScrollY(window.scrollY);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <div aria-hidden className="pointer-events-none absolute inset-0 overflow-hidden z-0">
      {/* 1. Large Baby Pacifier Top-Left (Parallax Speed: 0.18) */}
      <div
        className="absolute left-[8%] top-[8%] transition-transform duration-100 ease-out plane-float"
        style={{ transform: `translateY(${scrollY * 0.18}px) rotate(5deg)` }}
      >
        <PacifierBackgroundIcon size={46} />
      </div>

      {/* 2. Fluffy Cloud Top-Right (Parallax Speed: -0.08) */}
      <div
        className="absolute right-[10%] top-[14%] transition-transform duration-100 ease-out"
        style={{ transform: `translateY(${scrollY * -0.08}px)` }}
      >
        <SkyCloud width={130} height={75} />
      </div>

      {/* 3. Boss Sunglasses Mid-Left-Top (Parallax Speed: -0.25) */}
      <div
        className="absolute left-[5%] top-[25%] transition-transform duration-100 ease-out plane-float"
        style={{ transform: `translateY(${scrollY * -0.25}px) rotate(10deg)` }}
      >
        <SunglassesBackgroundIcon size={52} />
      </div>

      {/* 4. Soft Cloud Mid-Right (Parallax Speed: 0.14) */}
      <div
        className="absolute right-[8%] top-[34%] transition-transform duration-100 ease-out"
        style={{ transform: `translateY(${scrollY * 0.14}px)` }}
      >
        <SkyCloud width={140} height={80} className="text-white/40" />
      </div>

      {/* 5. Briefcase Mid-Left (Parallax Speed: 0.06) */}
      <div
        className="absolute left-[7%] top-[45%] transition-transform duration-100 ease-out plane-float"
        style={{ transform: `translateY(${scrollY * 0.06}px) rotate(-8deg)` }}
      >
        <BriefcaseBackgroundIcon size={46} />
      </div>

      {/* 6. Baby Bottle Mid-Right-Bottom (Parallax Speed: -0.18) */}
      <div
        className="absolute right-[6%] top-[56%] transition-transform duration-100 ease-out plane-float"
        style={{ transform: `translateY(${scrollY * -0.18}px) rotate(-5deg)` }}
      >
        <BottleBackgroundIcon size={48} />
      </div>

      {/* 7. Large Fluffy Cloud Bottom-Left (Parallax Speed: 0.22) */}
      <div
        className="absolute left-[9%] top-[68%] transition-transform duration-100 ease-out"
        style={{ transform: `translateY(${scrollY * 0.22}px)` }}
      >
        <SkyCloud width={150} height={85} className="text-white/45" />
      </div>

      {/* 8. Sunglasses Bottom-Left (Parallax Speed: -0.15) */}
      <div
        className="absolute left-[6%] top-[78%] transition-transform duration-100 ease-out plane-float"
        style={{ transform: `translateY(${scrollY * -0.15}px) rotate(12deg)` }}
      >
        <SunglassesBackgroundIcon size={48} />
      </div>

      {/* 9. Pacifier Bottom-Right (Parallax Speed: 0.25) */}
      <div
        className="absolute right-[9%] top-[88%] transition-transform duration-100 ease-out plane-float"
        style={{ transform: `translateY(${scrollY * 0.25}px) rotate(-15deg)` }}
      >
        <PacifierBackgroundIcon size={44} className="text-sky-400/35" />
      </div>
    </div>
  );
}
export default SkyBackground;
